changeSet.sql:
UPDATE task_status SET code = 'Backlog'     WHERE code IN ('BACKLOG', 'Бэклог')          AND default_task_status = true;
UPDATE task_status SET code = 'To Do'       WHERE code IN ('TODO', 'К выполнению');
UPDATE task_status SET code = 'In Progress' WHERE code IN ('IN_PROGRESS', 'В работе');
UPDATE task_status SET code = 'Review'      WHERE code IN ('REVIEW', 'Ревью');
UPDATE task_status SET code = 'Done'        WHERE code IN ('DONE', 'Готово');
UPDATE task_status SET code = 'Canceled'    WHERE code IN ('CANCELED', 'Отменена');
